const STATUS = {
  HEALTHY: { bg: "bg-emerald-50", border: "border-emerald-300", text: "text-emerald-700", dot: "bg-emerald-500", label: "HEALTHY" },
  WARNING: { bg: "bg-amber-50",   border: "border-amber-300",   text: "text-amber-700",   dot: "bg-amber-500",   label: "WARNING" },
  CRITICAL:{ bg: "bg-red-50",     border: "border-red-300",     text: "text-red-700",      dot: "bg-red-500",     label: "CRITICAL" },
};
const s = (k) => STATUS[k] || STATUS.HEALTHY;

export default function App() {
  const [tab, setTab] = useState("overview");
  const tabs = [
    { id:"overview",       label:"🌐 Übersicht" },
    { id:"apps",           label:"☁️ CF Apps" },
    { id:"quota",          label:"📊 Quota" },
    { id:"security",       label:"🔐 Security" },
    { id:"subscriptions",  label:"📦 SaaS" },
  ];

  const overall = RAW.overall || "HEALTHY";
  const ga      = RAW.globalAccount || {};
  const subs    = RAW.subaccounts   || [];
  const cfApps  = RAW.cfApps        || {};
  const quota   = RAW.quota         || {};
  const sec     = RAW.security      || {};
  const saas    = { all: (RAW.subscriptions || []).flatMap(sub => (sub.apps || []).map(a => ({ ...a, subaccount: sub.subaccount, state: sub.failed > 0 ? "FAILED" : "SUBSCRIBED" }))), total: (RAW.subscriptions || []).reduce((sum, sub) => sum + (sub.subscribed || 0), 0), failed: (RAW.subscriptions || []).reduce((sum, sub) => sum + (sub.failed || 0), 0) };

  // flat list of apps
  const allApps = Object.entries(cfApps.perSubaccount || {}).flatMap(([saName, bucket]) =>
    (bucket.apps || []).map(a => ({ ...a, subaccount: saName }))
  );

  // quota chart data
  const quotaChart = [
    ...(quota.critical || []).map(q => ({ name: q.service, pct: q.usagePercent, fill: "#ef4444" })),
    ...(quota.warning  || []).map(q => ({ name: q.service, pct: q.usagePercent, fill: "#f59e0b" })),
  ];

  // flatten all admins for security tab
  const allAdmins = [
    ...(sec.globalAdmins || []).map(a => ({ ...a, subaccount: "Global Account" })),
    ...Object.entries(sec.subaccountAdmins || {}).flatMap(([saName, admins]) =>
      admins.map(a => ({ ...a, subaccount: saName.split(" (")[0] }))
    ),
  ];

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-sm">
      {/* Header */}
      <div className={`px-6 py-4 ${s(overall).bg} border-b ${s(overall).border}`}>
        <div className="flex items-center gap-3">
          <span className={`w-3 h-3 rounded-full ${s(overall).dot}`} />
          <h1 className="text-xl font-bold text-gray-800">BTP Health Dashboard — {ga.name || "Global Account"}</h1>
          <span className={`ml-auto px-2 py-0.5 rounded text-xs font-semibold ${s(overall).text} ${s(overall).bg} border ${s(overall).border}`}>{overall}</span>
        </div>
        <p className="text-gray-500 text-xs mt-1">{RAW.timestamp || ""} · {subs.length} Subaccounts · {cfApps.total || 0} CF Apps</p>
      </div>

      {/* KPI row */}
      <div className="grid grid-cols-5 gap-3 px-6 py-4">
        {[
          { label:"CF Apps", value: cfApps.total || 0, sub: `${cfApps.started||0} started`, color:"blue" },
          { label:"Gestoppt", value: cfApps.stopped||0, sub:"apps", color: cfApps.stopped?"yellow":"gray" },
          { label:"Kritische Quota", value:(quota.critical||[]).length, sub:"services 100%", color:(quota.critical||[]).length?"red":"gray" },
          { label:"Admins", value:allAdmins.length, sub:"users", color:"purple" },
          { label:"SaaS", value:saas.total||0, sub:`${saas.failed||0} failed`, color:saas.failed?"red":"gray" },
        ].map(k => (
          <div key={k.label} className="bg-white rounded-xl border border-gray-200 p-4 text-center shadow-sm">
            <div className={`text-3xl font-bold text-${k.color}-600`}>{k.value}</div>
            <div className="font-medium text-gray-700 mt-1">{k.label}</div>
            <div className="text-xs text-gray-400">{k.sub}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="px-6 flex gap-1 border-b border-gray-200">
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`px-4 py-2 text-sm font-medium transition-colors ${tab===t.id ? "border-b-2 border-blue-600 text-blue-700" : "text-gray-500 hover:text-gray-700"}`}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="px-6 py-4">

        {/* OVERVIEW */}
        {tab==="overview" && (
          <div className="grid grid-cols-3 gap-3">
            {subs.map(sa => {
              const st = s(sa.status);
              return (
                <div key={sa.guid} className={`rounded-xl border ${st.border} ${st.bg} p-4 shadow-sm`}>
                  <div className="flex items-center gap-2 mb-2">
                    <span className={`w-2 h-2 rounded-full ${st.dot}`} />
                    <span className="font-semibold text-gray-800 truncate">{sa.name}</span>
                  </div>
                  <div className={`text-xs font-medium ${st.text}`}>{sa.status}</div>
                  <div className="text-xs text-gray-400 mt-1">{sa.region} · {sa.state}</div>
                </div>
              );
            })}
          </div>
        )}

        {/* CF APPS */}
        {tab==="apps" && (
          <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["Subaccount","App","State","Instances","Memory","Disk"].map(h=>(
                  <th key={h} className="px-4 py-3 text-left font-semibold text-gray-600">{h}</th>
                ))}</tr>
              </thead>
              <tbody>
                {allApps.map((a,i) => (
                  <tr key={i} className={`border-b border-gray-100 ${a.crashed?"bg-red-50":a.state!=="STARTED"?"bg-amber-50":i%2===0?"bg-white":"bg-gray-50"}`}>
                    <td className="px-4 py-2 text-gray-500 text-xs">{a.subaccount}</td>
                    <td className="px-4 py-2 font-medium">{a.name}</td>
                    <td className="px-4 py-2">
                      <span className={`px-2 py-0.5 rounded text-xs font-semibold ${a.state==="STARTED"?"bg-emerald-100 text-emerald-700":a.crashed?"bg-red-100 text-red-700":"bg-amber-100 text-amber-700"}`}>
                        {a.crashed?"CRASHED":a.state}
                      </span>
                    </td>
                    <td className="px-4 py-2 text-gray-600">{a.instances ?? "–"}</td>
                    <td className="px-4 py-2 text-gray-600">{a.memoryMB ? a.memoryMB+"MB" : "–"}</td>
                    <td className="px-4 py-2 text-gray-600">{a.diskMB ? a.diskMB+"MB" : "–"}</td>
                  </tr>
                ))}
                {allApps.length===0 && <tr><td colSpan={6} className="px-4 py-8 text-center text-gray-400">Keine Apps gefunden</td></tr>}
              </tbody>
            </table>
          </div>
        )}

        {/* QUOTA */}
        {tab==="quota" && (
          <div className="space-y-4">
            {quotaChart.length > 0 && (
              <div className="bg-white rounded-xl border border-gray-200 p-4 shadow-sm">
                <h3 className="font-semibold text-gray-700 mb-3">Quota-Auslastung (%)</h3>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={quotaChart} layout="vertical">
                    <XAxis type="number" domain={[0,100]} tickFormatter={v=>v+"%"} />
                    <YAxis type="category" dataKey="name" width={160} tick={{fontSize:11}} />
                    <Tooltip formatter={v=>v+"%"} />
                    <Bar dataKey="pct" radius={[0,4,4,0]}>
                      {quotaChart.map((q,i)=><Cell key={i} fill={q.fill} />)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            )}
            <div className="space-y-2">
              {[...(quota.critical||[]).map(q=>({...q,sev:"CRITICAL"})), ...(quota.warning||[]).map(q=>({...q,sev:"WARNING"}))].map((q,i)=>(
                <div key={i} className={`flex items-center justify-between rounded-lg border p-3 ${q.sev==="CRITICAL"?"bg-red-50 border-red-200":"bg-amber-50 border-amber-200"}`}>
                  <div>
                    <span className="font-medium">{q.service}</span>
                    <span className="text-gray-400 text-xs ml-2">{q.plan}</span>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="text-xs text-gray-500">{q.used} / {q.entitled}</span>
                    <span className={`px-2 py-0.5 rounded text-xs font-bold ${q.sev==="CRITICAL"?"bg-red-600 text-white":"bg-amber-500 text-white"}`}>{q.usagePercent}%</span>
                  </div>
                </div>
              ))}
              {quotaChart.length===0 && <p className="text-gray-400 text-center py-8">Keine kritischen Quotas</p>}
            </div>
          </div>
        )}

        {/* SECURITY */}
        {tab==="security" && (
          <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["User","Subaccount","Admin Roles","Alle Roles"].map(h=>(
                  <th key={h} className="px-4 py-3 text-left font-semibold text-gray-600">{h}</th>
                ))}</tr>
              </thead>
              <tbody>
                {allAdmins.map((a,i)=>(
                  <tr key={i} className={`border-b border-gray-100 ${i%2===0?"bg-white":"bg-gray-50"}`}>
                    <td className="px-4 py-2 font-medium">{a.email||a.userName||a.origin}</td>
                    <td className="px-4 py-2 text-gray-500 text-xs">{a.subaccount}</td>
                    <td className="px-4 py-2"><span className="px-2 py-0.5 bg-red-100 text-red-700 rounded text-xs font-semibold">{a.adminRoleCount}</span></td>
                    <td className="px-4 py-2 text-gray-400">{a.totalRoleCount}</td>
                  </tr>
                ))}
                {!allAdmins.length && <tr><td colSpan={4} className="px-4 py-8 text-center text-gray-400">Keine Admin-User gefunden</td></tr>}
              </tbody>
            </table>
          </div>
        )}

        {/* SUBSCRIPTIONS */}
        {tab==="subscriptions" && (
          <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>{["App","Plan","Subaccount","Status"].map(h=>(
                  <th key={h} className="px-4 py-3 text-left font-semibold text-gray-600">{h}</th>
                ))}</tr>
              </thead>
              <tbody>
                {(saas.all||[]).map((s,i)=>(
                  <tr key={i} className={`border-b border-gray-100 ${s.state!=="SUBSCRIBED"?"bg-amber-50":i%2===0?"bg-white":"bg-gray-50"}`}>
                    <td className="px-4 py-2 font-medium">{s.appName||s.commercialAppName}</td>
                    <td className="px-4 py-2 text-gray-500 text-xs">{s.planName||"–"}</td>
                    <td className="px-4 py-2 text-gray-500 text-xs">{s.subaccount}</td>
                    <td className="px-4 py-2">
                      <span className={`px-2 py-0.5 rounded text-xs font-semibold ${s.state==="SUBSCRIBED"?"bg-emerald-100 text-emerald-700":"bg-amber-100 text-amber-700"}`}>{s.state}</span>
                    </td>
                  </tr>
                ))}
                {!(saas.all||[]).length && <tr><td colSpan={4} className="px-4 py-8 text-center text-gray-400">Keine Subscriptions gefunden</td></tr>}
              </tbody>
            </table>
          </div>
        )}

      </div>
    </div>
  );
}
